"Here is a method in Java to convert a string to title case while handling exception words:

```java
public class TitleCaseConverter {
    private static final List<String> EXCEPTION_WORDS = List.of("of", "the", "is", "and");

    public static String convertToTitleCase(String input) {
        if (input == null || input.isEmpty()) {
            return input;
        }

        StringBuilder result = new StringBuilder();
        boolean isFirstWord = true;

        for (int i = 0; i < input.length(); i++) {
            char currentChar = input.charAt(i);

            if (i == 0) {
                // First character is always capitalized
                result.append(Character.toUpperCase(currentChar));
            } else {
                // Check if current character is a letter
                if (Character.isLetter(currentChar)) {
                    // Check if current word is an exception word
                    if (isExceptionWord(currentChar, i, input)) {
                        result.append(currentChar);
                    } else {
                        // Capitalize the letter if it's not the first word and not an exception word
                        result.append(Character.toUpperCase(currentChar));
                    }
                } else {
                    // Non-letter character, leave as is
                    result.append(currentChar);
                }
            }
        }

        return result.toString();
    }

    private static boolean isExceptionWord(char currentChar, int i, String input) {
        // Check if current character is part of an exception word
        if (i == 0) {
            return false;
        }

        // Check if the current character is the first character of an exception word
        if (Character.isLetter(currentChar)) {
            String word = Character.toString(currentChar) + input.substring(i);
            return EXCEPTION_WORDS.contains(word);
        }

        return false;
    }
}
